    private readonly ForgotPasswordModel _model = new();
    private bool _isLoading = false;
    private bool _emailSent = false;

    private async Task RequestPasswordReset()
    {
        try
        {
            _isLoading = true;
            var result = await AuthService.RequestPasswordResetAsync(_model.Email);

            if (result.IsSuccess)
            {
                _emailSent = true;
                Snackbar.Add("Reset-Link wurde erfolgreich gesendet!", Severity.Success);
            }
            else
            {
                Snackbar.Add($"Fehler beim Senden: {result.Error}", Severity.Error);
            }
        }
        catch (Exception ex)
        {
            Snackbar.Add($"Ein Fehler ist aufgetreten: {ex.Message}", Severity.Error);
        }
        finally
        {
            _isLoading = false;
        }
    }

    public class ForgotPasswordModel
    {
        public string Email { get; set; } = string.Empty;
